// =============================================================
// Fetch & Initialize — the orchestrator brain
// =============================================================
// Reads webhook body, fetches workflow + steps + edges from
// Supabase, creates execution + step execution records,
// topologically sorts steps, builds trigger context, and
// returns the sorted step list for SplitInBatches processing.
// =============================================================

const Sentry = require('@sentry/node');
const https = require('https');

const SUPABASE_URL = 'https://zujwhdoickvsotbrqkot.supabase.co';
const SUPABASE_KEY = $env.SUPABASE_SERVICE_ROLE_KEY;

// ---- Supabase helper (native https, no SDK) ----

async function supabaseRequest(path, method, body) {
  const url = `${SUPABASE_URL}/rest/v1/${path}`;
  return new Promise((resolve, reject) => {
    const parsed = new URL(url);
    const options = {
      hostname: parsed.hostname,
      path: parsed.pathname + parsed.search,
      method: method || 'GET',
      headers: {
        'apikey': SUPABASE_KEY,
        'Authorization': `Bearer ${SUPABASE_KEY}`,
        'Content-Type': 'application/json',
        'Prefer': method === 'POST' ? 'return=representation' : 'return=representation',
      },
    };
    const req = https.request(options, (res) => {
      let data = '';
      res.on('data', (chunk) => data += chunk);
      res.on('end', () => {
        try {
          const parsed = JSON.parse(data);
          if (res.statusCode >= 400) {
            reject(new Error(`Supabase ${method} ${path} returned ${res.statusCode}: ${data}`));
          } else {
            resolve(parsed);
          }
        } catch (e) {
          reject(new Error(`Parse error for ${path}: ${data}`));
        }
      });
    });
    req.on('error', reject);
    if (body) req.write(JSON.stringify(body));
    req.end();
  });
}

function uuid() {
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, (c) => {
    const r = Math.random() * 16 | 0;
    const v = c === 'x' ? r : (r & 0x3 | 0x8);
    return v.toString(16);
  });
}

// ---- Topological sort (Kahn's algorithm — ported from CMS utils.ts) ----

function topologicalSort(steps, edges) {
  const stepMap = new Map(steps.map(s => [s.id, s]));
  const inDegree = new Map();
  const adjacency = new Map();

  for (const step of steps) {
    inDegree.set(step.id, 0);
    adjacency.set(step.id, []);
  }

  for (const edge of edges) {
    if (!stepMap.has(edge.source_step_id) || !stepMap.has(edge.target_step_id)) continue;
    adjacency.get(edge.source_step_id).push(edge.target_step_id);
    inDegree.set(edge.target_step_id, (inDegree.get(edge.target_step_id) || 0) + 1);
  }

  const queue = [];
  for (const [id, degree] of inDegree) {
    if (degree === 0) queue.push(id);
  }

  const sorted = [];
  while (queue.length > 0) {
    const current = queue.shift();
    const step = stepMap.get(current);
    if (step) sorted.push(step);
    for (const neighbor of (adjacency.get(current) || [])) {
      const newDeg = (inDegree.get(neighbor) || 1) - 1;
      inDegree.set(neighbor, newDeg);
      if (newDeg === 0) queue.push(neighbor);
    }
  }

  if (sorted.length !== steps.length) {
    throw new Error(`Workflow graph contains a cycle. Sorted ${sorted.length} of ${steps.length} steps.`);
  }
  return sorted;
}

// ---- Build trigger context (ported from CMS utils.ts) ----

function buildTriggerContext(triggerType, payload) {
  const base = { trigger_type: triggerType };
  switch (triggerType) {
    case 'survey_submitted':
      return { ...base, responseId: payload.responseId, surveyLinkId: payload.surveyLinkId };
    case 'booking_created':
      return {
        ...base,
        appointmentId: payload.appointmentId,
        ...(payload.responseId && { responseId: payload.responseId }),
        ...(payload.surveyLinkId && { surveyLinkId: payload.surveyLinkId }),
        ...(payload.clientEmail && { clientEmail: payload.clientEmail }),
        ...(payload.appointmentAt && { appointmentAt: payload.appointmentAt }),
      };
    case 'lead_scored':
      return {
        ...base,
        responseId: payload.responseId,
        overallScore: payload.score,
        recommendation: payload.recommendation,
        ...(payload.summary && { summary: payload.summary }),
        ...(payload.analyzedAt && { analyzedAt: payload.analyzedAt }),
      };
    default:
      return base;
  }
}

// ---- Main logic ----

try {
  const webhookBody = $('Webhook').first().json.body;
  const { workflowId, triggerPayload, tenantId } = webhookBody;

  if (!workflowId || !tenantId) {
    throw new Error('Missing required fields: workflowId and tenantId');
  }

  // 1. Fetch workflow
  const workflows = await supabaseRequest(
    `workflows?id=eq.${workflowId}&tenant_id=eq.${tenantId}&is_active=eq.true&limit=1`, 'GET'
  );
  if (!workflows.length) {
    throw new Error(`Workflow ${workflowId} not found or not active for tenant ${tenantId}`);
  }
  const workflow = workflows[0];

  // 2. Fetch steps (exclude trigger-type steps — executor skips them)
  const allSteps = await supabaseRequest(
    `workflow_steps?workflow_id=eq.${workflowId}&order=position.asc`, 'GET'
  );
  // Filter out trigger-type steps
  const TRIGGER_TYPES = ['survey_submitted', 'booking_created', 'lead_scored', 'manual', 'scheduled'];
  const steps = allSteps.filter(s => !TRIGGER_TYPES.includes(s.step_type));

  if (steps.length === 0) {
    throw new Error(`Workflow ${workflowId} has no executable steps`);
  }

  // 3. Fetch edges
  const edges = await supabaseRequest(
    `workflow_edges?workflow_id=eq.${workflowId}`, 'GET'
  );

  // 4. Circular protection — max depth 1
  if (triggerPayload && triggerPayload.triggeringExecutionId) {
    const parentExecs = await supabaseRequest(
      `workflow_executions?id=eq.${triggerPayload.triggeringExecutionId}&limit=1`, 'GET'
    );
    if (parentExecs.length && parentExecs[0].triggering_execution_id) {
      throw new Error('Circular workflow detected: max depth (1) exceeded');
    }
  }

  // 5. Create execution record
  const executionId = uuid();
  const triggerType = triggerPayload?.trigger_type || 'manual';
  const execRecords = await supabaseRequest('workflow_executions', 'POST', {
    id: executionId,
    workflow_id: workflowId,
    tenant_id: tenantId,
    status: 'running',
    trigger_type: triggerType,
    trigger_payload: triggerPayload || {},
    triggering_execution_id: triggerPayload?.triggeringExecutionId || null,
    started_at: new Date().toISOString(),
  });

  // 6. Create step execution records
  const stepExecRecords = steps.map(step => ({
    id: uuid(),
    execution_id: executionId,
    step_id: step.id,
    status: 'pending',
    started_at: null,
    completed_at: null,
    output_payload: null,
    error_message: null,
  }));
  await supabaseRequest('workflow_step_executions', 'POST', stepExecRecords);

  // Build step_id → step_execution_id map
  const stepExecMap = {};
  for (const se of stepExecRecords) {
    stepExecMap[se.step_id] = se.id;
  }

  // 7. Topological sort
  const sortedSteps = topologicalSort(steps, edges);

  // 8. Build trigger context
  const variableContext = buildTriggerContext(triggerType, triggerPayload || {});

  // 9. Build output items for SplitInBatches
  const items = sortedSteps.map((step, index) => ({
    json: {
      step,
      stepIndex: index,
      totalSteps: sortedSteps.length,
      stepExecutionId: stepExecMap[step.id],
      executionId,
      workflowId,
      tenantId,
      variableContext,
      edges,
      allStepExecRecords: stepExecRecords,
      failed: false,
    }
  }));

  Sentry.addBreadcrumb({
    message: `Orchestrator initialized: ${sortedSteps.length} steps for workflow ${workflowId}`,
    level: 'info',
  });

  return items;

} catch (err) {
  Sentry.captureException(err);
  await Sentry.flush(2000);
  throw err;
}

// =============================================================
// Prepare Current Step — resolves variables and marks step running
// =============================================================

const Sentry = require('@sentry/node');
const https = require('https');

const SUPABASE_URL = 'https://zujwhdoickvsotbrqkot.supabase.co';
const SUPABASE_KEY = $env.SUPABASE_SERVICE_ROLE_KEY;

async function supabasePatch(path, body) {
  const url = `${SUPABASE_URL}/rest/v1/${path}`;
  return new Promise((resolve, reject) => {
    const parsed = new URL(url);
    const options = {
      hostname: parsed.hostname,
      path: parsed.pathname + parsed.search,
      method: 'PATCH',
      headers: {
        'apikey': SUPABASE_KEY,
        'Authorization': `Bearer ${SUPABASE_KEY}`,
        'Content-Type': 'application/json',
        'Prefer': 'return=representation',
      },
    };
    const req = https.request(options, (res) => {
      let data = '';
      res.on('data', (chunk) => data += chunk);
      res.on('end', () => {
        if (res.statusCode >= 400) {
          reject(new Error(`Supabase PATCH ${path}: ${res.statusCode} ${data}`));
        } else {
          resolve(data ? JSON.parse(data) : null);
        }
      });
    });
    req.on('error', reject);
    req.write(JSON.stringify(body));
    req.end();
  });
}

// Resolve {{variable}} placeholders in strings
function resolveVariables(template, context) {
  if (typeof template !== 'string') return template;
  return template.replace(/\{\{(\s*[\w.]+\s*)\}\}/g, (_, rawKey) => {
    const key = rawKey.trim();
    const value = getNestedValue(context, key);
    return (value !== undefined && value !== null) ? String(value) : `{{${key}}}`;
  });
}

function getNestedValue(obj, path) {
  const parts = path.split('.');
  let current = obj;
  for (const part of parts) {
    if (current === null || current === undefined || typeof current !== 'object') return undefined;
    current = current[part];
  }
  return current;
}

// Deep-resolve all string values in an object
function resolveDeep(obj, context) {
  if (typeof obj === 'string') return resolveVariables(obj, context);
  if (Array.isArray(obj)) return obj.map(item => resolveDeep(item, context));
  if (obj && typeof obj === 'object') {
    const result = {};
    for (const [key, value] of Object.entries(obj)) {
      result[key] = resolveDeep(value, context);
    }
    return result;
  }
  return obj;
}

try {
  const item = $input.first().json;

  // If previous step failed, skip all remaining
  if (item.failed) {
    return { json: item };
  }

  const { step, stepExecutionId, variableContext } = item;

  // Mark step as running in DB
  await supabasePatch(
    `workflow_step_executions?id=eq.${stepExecutionId}`,
    { status: 'running', started_at: new Date().toISOString() }
  );

  // Resolve variables in step_config
  const resolvedConfig = resolveDeep(step.step_config, variableContext);

  Sentry.addBreadcrumb({
    message: `Step ${item.stepIndex + 1}/${item.totalSteps}: ${step.step_type} (${step.name || step.id})`,
    level: 'info',
  });

  return {
    json: {
      ...item,
      resolvedConfig,
      stepType: step.step_type,
    }
  };
} catch (err) {
  Sentry.captureException(err);
  await Sentry.flush(2000);
  throw err;
}

// =============================================================
// Build Email Payload — fetch template, resolve recipient
// =============================================================

const Sentry = require('@sentry/node');
const https = require('https');

const SUPABASE_URL = 'https://zujwhdoickvsotbrqkot.supabase.co';
const SUPABASE_KEY = $env.SUPABASE_SERVICE_ROLE_KEY;

async function supabaseGet(path) {
  const url = `${SUPABASE_URL}/rest/v1/${path}`;
  return new Promise((resolve, reject) => {
    const parsed = new URL(url);
    const req = https.request({
      hostname: parsed.hostname,
      path: parsed.pathname + parsed.search,
      method: 'GET',
      headers: {
        'apikey': SUPABASE_KEY,
        'Authorization': `Bearer ${SUPABASE_KEY}`,
        'Content-Type': 'application/json',
      },
    }, (res) => {
      let data = '';
      res.on('data', (chunk) => data += chunk);
      res.on('end', () => {
        try { resolve(JSON.parse(data)); }
        catch (e) { reject(new Error(`Parse error: ${data}`)); }
      });
    });
    req.on('error', reject);
    req.end();
  });
}

function resolveVariables(template, context) {
  if (typeof template !== 'string') return template;
  return template.replace(/\{\{(\s*[\w.]+\s*)\}\}/g, (_, rawKey) => {
    const key = rawKey.trim();
    const value = getNestedValue(context, key);
    return (value !== undefined && value !== null) ? String(value) : `{{${key}}}`;
  });
}

function getNestedValue(obj, path) {
  const parts = path.split('.');
  let current = obj;
  for (const part of parts) {
    if (current === null || current === undefined || typeof current !== 'object') return undefined;
    current = current[part];
  }
  return current;
}

try {
  const item = $input.first().json;
  const { resolvedConfig, variableContext, tenantId } = item;

  const templateId = resolvedConfig.template_id;
  let subject = resolvedConfig.subject || 'Notification';
  let html = resolvedConfig.html_body || '<p>Notification</p>';

  // Fetch email template if template_id provided
  if (templateId) {
    const templates = await supabaseGet(`email_templates?id=eq.${templateId}&limit=1`);
    if (templates.length && templates[0].html_body) {
      subject = templates[0].subject || subject;
      html = templates[0].html_body;
    }
  }

  // Determine recipient
  let to = resolvedConfig.to;
  if (!to && variableContext.responseId) {
    // Fetch response → survey_link → notification_email
    const responses = await supabaseGet(`responses?id=eq.${variableContext.responseId}&limit=1`);
    if (responses.length) {
      const surveyLinks = await supabaseGet(`survey_links?id=eq.${responses[0].survey_link_id}&limit=1`);
      if (surveyLinks.length) {
        to = surveyLinks[0].notification_email;
      }
    }
  }

  if (!to) throw new Error('No recipient email resolved for send_email step');

  // Resolve variables in subject and html
  subject = resolveVariables(subject, variableContext);
  html = resolveVariables(html, variableContext);

  return {
    json: {
      ...item,
      emailPayload: { to, subject, html, tenant_id: tenantId },
    }
  };
} catch (err) {
  Sentry.captureException(err);
  await Sentry.flush(2000);
  // Return failure result instead of throwing — Process Step Result handles it
  const item = $input.first().json;
  return {
    json: {
      ...item,
      stepResult: { success: false, error: err.message },
    }
  };
}

// Build AI Payload for MiniMax Agent subworkflow
const item = $input.first().json;
const { resolvedConfig, variableContext } = item;

const prompt = resolvedConfig.prompt || '';
const outputSchema = resolvedConfig.output_schema || [];

// Build context string from variable context
const contextEntries = Object.entries(variableContext)
  .map(([k, v]) => `${k}: ${JSON.stringify(v)}`)
  .join('\n');

return {
  json: {
    ...item,
    aiPayload: {
      prompt,
      context: contextEntries,
      output_schema: outputSchema,
      tenant_id: item.tenantId,
    },
  }
};

// =============================================================
// SSRF Check — block private IPs before HTTP Request
// =============================================================

const item = $input.first().json;
const { resolvedConfig } = item;
const url = resolvedConfig.url;

if (!url) {
  return {
    json: {
      ...item,
      stepResult: { success: false, error: 'Webhook step missing url in config' },
    }
  };
}

try {
  const parsed = new URL(url);
  const hostname = parsed.hostname.toLowerCase();

  const privatePatterns = [
    /^10\./,
    /^172\.(1[6-9]|2\d|3[01])\./,
    /^192\.168\./,
    /^127\./,
    /^localhost$/i,
    /^::1$/,
    /\.local$/,
    /^0\.0\.0\.0$/,
    /^169\.254\./,
  ];

  const isPrivate = privatePatterns.some(p => p.test(hostname));
  if (isPrivate) {
    return {
      json: {
        ...item,
        stepResult: { success: false, error: `Webhook URL targets private address: ${hostname}` },
      }
    };
  }

  return { json: { ...item, webhookUrl: url, webhookMethod: resolvedConfig.method || 'POST' } };
} catch (e) {
  return {
    json: {
      ...item,
      stepResult: { success: false, error: `Invalid webhook URL: ${url}` },
    }
  };
}

// =============================================================
// Evaluate Condition — ported from CMS condition-evaluator.ts
// =============================================================

const Sentry = require('@sentry/node');

const OPERATORS = ['>=', '<=', '!=', '==', '>', '<', 'contains', 'in'];

function escapeRegex(str) {
  return str.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
}

function parseExpression(expression) {
  const trimmed = expression.trim();
  for (const op of OPERATORS) {
    const pattern = (op === 'contains' || op === 'in')
      ? new RegExp(`^(.+?)\\s+${op}\\s+(.+)$`)
      : new RegExp(`^(.+?)\\s*${escapeRegex(op)}\\s*(.+)$`);
    const match = trimmed.match(pattern);
    if (match) {
      return { field: match[1].trim(), operator: op, value: match[2].trim() };
    }
  }
  return null;
}

function getNestedValue(obj, path) {
  const parts = path.split('.');
  let current = obj;
  for (const part of parts) {
    if (current === null || current === undefined || typeof current !== 'object') return undefined;
    current = current[part];
  }
  return current;
}

function resolveField(field, context) {
  const cleanField = field.replace(/^\{\{|\}\}$/g, '').trim();
  return getNestedValue(context, cleanField);
}

function coerceNumeric(value) {
  const num = Number(value);
  return Number.isNaN(num) ? value : num;
}

function compare(fieldValue, operator, rawValue) {
  switch (operator) {
    case '==':
      return String(fieldValue) === rawValue;
    case '!=':
      return String(fieldValue) !== rawValue;
    case '>': case '<': case '>=': case '<=': {
      const left = typeof fieldValue === 'number' ? fieldValue : Number(fieldValue);
      const right = coerceNumeric(rawValue);
      if (typeof right !== 'number' || Number.isNaN(left)) return false;
      if (operator === '>') return left > right;
      if (operator === '<') return left < right;
      if (operator === '>=') return left >= right;
      if (operator === '<=') return left <= right;
      return false;
    }
    case 'contains':
      return String(fieldValue).includes(rawValue);
    case 'in': {
      const list = rawValue.split(',').map(v => v.trim());
      return list.includes(String(fieldValue));
    }
  }
  return false;
}

function evaluateCondition(expression, context) {
  const parsed = parseExpression(expression);
  if (!parsed) return 'false';
  const fieldValue = resolveField(parsed.field, context);
  if (fieldValue === undefined) return 'false';
  return compare(fieldValue, parsed.operator, parsed.value) ? 'true' : 'false';
}

// ---- Main ----

try {
  const item = $input.first().json;
  const { resolvedConfig, variableContext, step, edges, allStepExecRecords } = item;

  const expression = resolvedConfig.expression || '';
  const branch = evaluateCondition(expression, variableContext);

  Sentry.addBreadcrumb({
    message: `Condition '${expression}' evaluated to '${branch}'`,
    level: 'info',
  });

  // Mark steps on non-taken branch as skipped
  // Find edges from this condition step
  const conditionEdges = edges.filter(e => e.source_step_id === step.id);
  const skipTargetIds = new Set();

  for (const edge of conditionEdges) {
    // Skip edges on the non-taken branch
    if (edge.condition_branch && edge.condition_branch !== branch) {
      skipTargetIds.add(edge.target_step_id);
    }
  }

  // Recursively find all downstream steps only reachable from skipped steps
  // A step is skipped only if ALL its incoming edges come from skipped steps
  const allSkipped = new Set(skipTargetIds);
  let changed = true;
  while (changed) {
    changed = false;
    for (const edge of edges) {
      if (allSkipped.has(edge.source_step_id) && !allSkipped.has(edge.target_step_id)) {
        // Check if ALL incoming edges to target come from skipped steps
        const incomingEdges = edges.filter(e => e.target_step_id === edge.target_step_id);
        const allIncomingSkipped = incomingEdges.every(e => allSkipped.has(e.source_step_id));
        if (allIncomingSkipped) {
          allSkipped.add(edge.target_step_id);
          changed = true;
        }
      }
    }
  }

  return {
    json: {
      ...item,
      stepResult: {
        success: true,
        outputPayload: { branch },
      },
      skippedStepIds: Array.from(allSkipped),
    }
  };
} catch (err) {
  Sentry.captureException(err);
  await Sentry.flush(2000);
  const item = $input.first().json;
  return {
    json: {
      ...item,
      stepResult: { success: false, error: err.message },
    }
  };
}

// Delay step — not implemented in iteration 1, skip with warning
const Sentry = require('@sentry/node');
const item = $input.first().json;

Sentry.addBreadcrumb({
  message: 'Delay step skipped — not implemented until iteration 3',
  level: 'warning',
});

return {
  json: {
    ...item,
    stepResult: {
      success: true,
      outputPayload: { skipped: true, reason: 'delay step not implemented in orchestrator iteration 1' },
    },
  }
};

// Failed / skipped passthrough — just forward the item
const item = $input.first().json;
return { json: item };

// Unknown step type handler
const item = $input.first().json;
return {
  json: {
    ...item,
    stepResult: {
      success: false,
      error: `Unknown step type: ${item.stepType}`,
    },
  }
};

// =============================================================
// Process Step Result — update DB, merge context, handle failure
// =============================================================
// This node runs after every step type branch.
// It updates the step execution in DB, merges output into
// variableContext, and handles failure (marks remaining skipped).
// =============================================================

const Sentry = require('@sentry/node');
const https = require('https');

const SUPABASE_URL = 'https://zujwhdoickvsotbrqkot.supabase.co';
const SUPABASE_KEY = $env.SUPABASE_SERVICE_ROLE_KEY;

async function supabasePatch(path, body) {
  const url = `${SUPABASE_URL}/rest/v1/${path}`;
  return new Promise((resolve, reject) => {
    const parsed = new URL(url);
    const options = {
      hostname: parsed.hostname,
      path: parsed.pathname + parsed.search,
      method: 'PATCH',
      headers: {
        'apikey': SUPABASE_KEY,
        'Authorization': `Bearer ${SUPABASE_KEY}`,
        'Content-Type': 'application/json',
        'Prefer': 'return=representation',
      },
    };
    const req = https.request(options, (res) => {
      let data = '';
      res.on('data', (chunk) => data += chunk);
      res.on('end', () => {
        if (res.statusCode >= 400) {
          reject(new Error(`Supabase PATCH ${path}: ${res.statusCode} ${data}`));
        } else {
          resolve(data ? JSON.parse(data) : null);
        }
      });
    });
    req.on('error', reject);
    req.write(JSON.stringify(body));
    req.end();
  });
}

try {
  const item = $input.first().json;
  const { stepExecutionId, executionId, variableContext, step } = item;

  // If already in failed passthrough mode, just return
  if (item.failed) {
    return { json: item };
  }

  // Determine step result — some branches set it directly, others need extraction
  let stepResult = item.stepResult;

  // For send_email: result comes from Call Send Email subworkflow
  if (!stepResult && item.stepType === 'send_email') {
    if (item.emailPayload) {
      stepResult = { success: true, outputPayload: { emailSent: true, recipientEmail: item.emailPayload.to } };
    } else {
      stepResult = { success: false, error: 'Email payload not built' };
    }
  }

  // For ai_action: parse result from MiniMax Agent subworkflow
  if (!stepResult && item.stepType === 'ai_action') {
    try {
      // MiniMax Agent returns content[0].text — try to parse as JSON
      const aiOutput = $('Call MiniMax Agent').first().json;
      let parsedOutput = {};
      if (aiOutput && aiOutput.content && aiOutput.content[0] && aiOutput.content[0].text) {
        try {
          parsedOutput = JSON.parse(aiOutput.content[0].text);
        } catch {
          parsedOutput = { aiResponse: aiOutput.content[0].text };
        }
      } else if (aiOutput && aiOutput.text) {
        try {
          parsedOutput = JSON.parse(aiOutput.text);
        } catch {
          parsedOutput = { aiResponse: aiOutput.text || JSON.stringify(aiOutput) };
        }
      } else {
        parsedOutput = { aiResponse: JSON.stringify(aiOutput) };
      }
      stepResult = { success: true, outputPayload: parsedOutput };
    } catch (e) {
      stepResult = { success: false, error: `AI action failed: ${e.message}` };
    }
  }

  // For webhook: extract result from HTTP Request response
  if (!stepResult && item.stepType === 'webhook') {
    try {
      const httpResult = $('HTTP Webhook Request').first().json;
      stepResult = {
        success: true,
        outputPayload: {
          statusCode: httpResult.statusCode || 200,
          responseBody: typeof httpResult === 'string' ? httpResult : JSON.stringify(httpResult),
        },
      };
    } catch (e) {
      stepResult = { success: false, error: `Webhook failed: ${e.message}` };
    }
  }

  // Fallback if no result set
  if (!stepResult) {
    stepResult = { success: false, error: 'No step result produced' };
  }

  // Update step execution in DB
  const now = new Date().toISOString();
  if (stepResult.success) {
    await supabasePatch(
      `workflow_step_executions?id=eq.${stepExecutionId}`,
      {
        status: 'completed',
        completed_at: now,
        output_payload: JSON.stringify(stepResult.outputPayload || {}),
      }
    );
  } else {
    await supabasePatch(
      `workflow_step_executions?id=eq.${stepExecutionId}`,
      {
        status: 'failed',
        completed_at: now,
        error_message: stepResult.error || 'Unknown error',
      }
    );
  }

  // Handle skipped steps from condition branching
  const skippedStepIds = item.skippedStepIds || [];
  if (skippedStepIds.length > 0) {
    const allStepExecs = item.allStepExecRecords || [];
    for (const skipStepId of skippedStepIds) {
      const skipExec = allStepExecs.find(se => se.step_id === skipStepId);
      if (skipExec) {
        await supabasePatch(
          `workflow_step_executions?id=eq.${skipExec.id}`,
          { status: 'skipped', completed_at: now }
        );
      }
    }
  }

  // Merge output into variable context
  const updatedContext = { ...variableContext };
  if (stepResult.success && stepResult.outputPayload) {
    Object.assign(updatedContext, stepResult.outputPayload);
  }

  // If step failed: mark execution as failed and signal to skip remaining steps
  if (!stepResult.success) {
    await supabasePatch(
      `workflow_executions?id=eq.${executionId}`,
      { status: 'failed', completed_at: now, error_message: stepResult.error }
    );

    Sentry.captureException(new Error(`Step failed: ${step.step_type} — ${stepResult.error}`));
    await Sentry.flush(2000);

    return {
      json: {
        ...item,
        variableContext: updatedContext,
        failed: true,
        failureError: stepResult.error,
      }
    };
  }

  return {
    json: {
      ...item,
      variableContext: updatedContext,
      stepResult: null,
      skippedStepIds: null,
    }
  };

} catch (err) {
  Sentry.captureException(err);
  await Sentry.flush(2000);
  throw err;
}

