const Sentry = require('@sentry/node');
const https = require('https');

const SUPABASE_URL = 'https://zujwhdoickvsotbrqkot.supabase.co';
const SUPABASE_KEY = $env.SUPABASE_SERVICE_ROLE_KEY;

async function supabasePatch(path, body) {
  const url = `${SUPABASE_URL}/rest/v1/${path}`;
  return new Promise((resolve, reject) => {
    const parsed = new URL(url);
    const options = {
      hostname: parsed.hostname,
      path: parsed.pathname + parsed.search,
      method: 'PATCH',
      headers: {
        'apikey': SUPABASE_KEY,
        'Authorization': `Bearer ${SUPABASE_KEY}`,
        'Content-Type': 'application/json',
        'Prefer': 'return=representation',
      },
    };
    const req = https.request(options, (res) => {
      let data = '';
      res.on('data', (chunk) => data += chunk);
      res.on('end', () => {
        if (res.statusCode >= 400) {
          reject(new Error(`Supabase PATCH ${path}: ${res.statusCode} ${data}`));
        } else {
          resolve(data ? JSON.parse(data) : null);
        }
      });
    });
    req.on('error', reject);
    req.write(JSON.stringify(body));
    req.end();
  });
}

try {
  // Get the last item from the batch — contains final state
  const items = $input.all();
  const lastItem = items[items.length - 1].json;

  // If already failed, execution was already marked failed in Process Step Result
  if (lastItem.failed) {
    Sentry.addBreadcrumb({
      message: `Execution ${lastItem.executionId} already marked failed`,
      level: 'warning',
    });
    return { json: { executionId: lastItem.executionId, status: 'failed' } };
  }

  // Mark remaining pending step executions as skipped (e.g. from condition branches)
  // These were not reached during execution
  const now = new Date().toISOString();

  // Mark execution as completed
  await supabasePatch(
    `workflow_executions?id=eq.${lastItem.executionId}`,
    { status: 'completed', completed_at: now }
  );

  Sentry.addBreadcrumb({
    message: `Execution ${lastItem.executionId} completed successfully`,
    level: 'info',
  });

  return { json: { executionId: lastItem.executionId, status: 'completed' } };
} catch (err) {
  Sentry.captureException(err);
  await Sentry.flush(2000);
  throw err;
}
